var result,fileName,originCountrySelector=$("#origin-country-selector"),destinationCountrySelector=$("#destination-country-selector"),body=$("body"),githubDbFolder="/data/documents/",availableCountries=[{code:"RO",name:"Romania",file:"romania.json"}];function buildOriginCountrySelector(e){originCountrySelector.append('<option value="">Selectează o țară</option>');for(let n=0;n<e.length;n++){var t=e[n];t&&originCountrySelector.append(`<option value="${t.file}">${t.name}</option>`)}}function buildDestinationCountrySelector(e){for(let n=0;n<e.length;n++){var t=e[n];t.documents&&destinationCountrySelector.append(`<option value="${t.code}">${t.name}</option>`)}}function findCountry(e,t){return t.find(t=>t.code===e)}function buildResults(e){var t=$("#info"),n=$("#comment"),o=$("#source"),i=$("#result");t.text(`Pentru a călători în ${e.name} ai nevoie de ${e.documents}.`),n.text(e.comment),o.html(`<a target="_blank" rel="noopener" href="${e.source}">Sursa informațiilor</a>`),i.show(),body.toggleClass("results-visible")}function buildEditLink(e){$("#edit").html(`<a target="_blank" rel="noopener" href="${githubDbFolder}/${e}"><i class="fal fa-edit"></i> Corectează informațiile</a>`)}buildOriginCountrySelector(availableCountries),originCountrySelector.change((function(){fileName=$(this).val(),$.getJSON("/data/documents/"+fileName,(function(e){buildDestinationCountrySelector(result=e)}))})),destinationCountrySelector.change((function(){buildResults(findCountry($(this).val(),result)),buildEditLink(fileName)})),$("#toggle-menu").click((function(){$("body").toggleClass("menu-visible")}));